import{_ as t,c as l,o as a,ag as i}from"./chunks/framework.piE7uVCg.js";const f=JSON.parse('{"title":"Systevo","description":"","frontmatter":{},"headers":[],"relativePath":"securite/malade/systevo.md","filePath":"securite/malade/systevo.md"}'),n={name:"securite/malade/systevo.md"};function r(s,e,o,d,c,u){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="systevo" tabindex="-1"><a href="./readme.html">Systevo</a> <a class="header-anchor" href="#systevo" aria-label="Permalink to &quot;[Systevo](readme.md)&quot;">​</a></h1><h2 id="connexion-au-pc" tabindex="-1">Connexion au PC <a class="header-anchor" href="#connexion-au-pc" aria-label="Permalink to &quot;Connexion au PC&quot;">​</a></h2><ol><li>Installer <a href="https://forum.uvnc.com/viewtopic.php?t=37976" target="_blank" rel="noreferrer">ultraVNC</a></li><li>Fixer l&#39;adresse IP du pc <code>10.1.19.3</code></li><li>Lancer UtraVNC</li><li>se connecter avec l&#39;adresse <code>10.1.19.2</code></li><li>mp <code>galama</code></li></ol><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Après la mise à jour de la version du logiciel un mot de passe est demandé c&#39;est <code>4711</code></p><h2 id="activation-de-licence" tabindex="-1">Activation de licence <a class="header-anchor" href="#activation-de-licence" aria-label="Permalink to &quot;Activation de licence&quot;">​</a></h2><p>Il faut lancer l&#39;application <code>CP99</code> puis :</p><ol><li>Aller sur <code>Extra</code> puis <code>Manage Licences</code></li><li>Incrire</li><li>Scanner le Qr code avec un smartphone</li><li>Cliquer sur <code>Ajouter</code></li><li>Scanner le QR code sur le fichie de licence en haut à gauche et commencer par la licence principale ppuis les extensions s&#39;il y en a</li><li>Accepter</li><li>télécharger la licence</li><li>Dans manage licences importer la licence</li></ol><h2 id="configuration-des-controllers" tabindex="-1">Configuration des controllers <a class="header-anchor" href="#configuration-des-controllers" aria-label="Permalink to &quot;Configuration des controllers&quot;">​</a></h2><h2 id="config-de-bus" tabindex="-1">Config de bus <a class="header-anchor" href="#config-de-bus" aria-label="Permalink to &quot;Config de bus&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Fonction</th><th style="text-align:left;">Code</th><th style="text-align:left;">Raccourci</th></tr></thead><tbody><tr><td style="text-align:left;">Scan du bus</td><td style="text-align:left;">scanzbus</td><td style="text-align:left;">Shift + F4</td></tr><tr><td style="text-align:left;">Afficher la liste des équipements</td><td style="text-align:left;">viewscan</td><td style="text-align:left;">F4</td></tr><tr><td style="text-align:left;">Réadresser le BUS</td><td style="text-align:left;">adrzbus</td><td style="text-align:left;">Shift + F5</td></tr><tr><td style="text-align:left;">Générer la base de donnée</td><td style="text-align:left;">makedb</td><td style="text-align:left;">Shift + F3</td></tr><tr><td style="text-align:left;">Afficher la base de données</td><td style="text-align:left;">viewdb</td><td style="text-align:left;">F3</td></tr><tr><td style="text-align:left;">Analyser le bus</td><td style="text-align:left;">analysezbus</td><td style="text-align:left;">_</td></tr><tr><td style="text-align:left;">Analyser le bus avec les tensions</td><td style="text-align:left;">scanvoltage</td><td style="text-align:left;">_</td></tr><tr><td style="text-align:left;">Lister les défauts</td><td style="text-align:left;">faultlist</td><td style="text-align:left;">_</td></tr></tbody></table><h2 id="cp99" tabindex="-1">CP99 <a class="header-anchor" href="#cp99" aria-label="Permalink to &quot;CP99&quot;">​</a></h2><ul><li>Le nombre max de caractères est de 8 pour les noms des équipements.</li><li>Nommer par zone puis par chambre</li></ul><h2 id="mise-a-jour-des-controlleurs" tabindex="-1">Mise à jour des controlleurs <a class="header-anchor" href="#mise-a-jour-des-controlleurs" aria-label="Permalink to &quot;Mise à jour des controlleurs&quot;">​</a></h2><ul><li>Lancer CP99 config</li><li>Sélectionner le type de controlleur</li><li>mettre l&#39;adresse ip</li><li>envoyer</li></ul><h2 id="changer-la-langue-de-l-interface" tabindex="-1">Changer la langue de l&#39;interface <a class="header-anchor" href="#changer-la-langue-de-l-interface" aria-label="Permalink to &quot;Changer la langue de l&#39;interface&quot;">​</a></h2><p>Extras &gt; Options &gt; Sélection de la langue &gt; francais</p>',17)])])}const g=t(n,[["render",r]]);export{f as __pageData,g as default};
